// Carrega os dispositivos a ingerir e injeta os metadados do Config em cada item.
// PRODUÇÃO: substitua o array `provisions` por um fetch + parser da fonte oficial
// (HTTP Request -> Planalto/LexML -> parser Akoma Ntoso). Contrato de saída por item:
//   { citation_key, label, full_text, amended_by, valid_from (YYYY-MM-DD|null), verification }
// verification começa 'pendente'; só vira 'verificada' após conferência na fonte primária.
const cfg = $('Config').first().json;

const provisions = [
  {
    citation_key: 'art. 5º, caput, CF',
    label: 'art. 5º (caput)',
    full_text: 'Todos são iguais perante a lei, sem distinção de qualquer natureza, garantindo-se aos brasileiros e aos estrangeiros residentes no País a inviolabilidade do direito à vida, à liberdade, à igualdade, à segurança e à propriedade, nos termos seguintes:',
    amended_by: 'redação original',
    valid_from: '1988-10-05',
    verification: 'pendente'
  },
  {
    citation_key: 'art. 5º, LV, CF',
    label: 'art. 5º, inciso LV',
    full_text: 'aos litigantes, em processo judicial ou administrativo, e aos acusados em geral são assegurados o contraditório e a ampla defesa, com os meios e recursos a ela inerentes;',
    amended_by: 'redação original',
    valid_from: '1988-10-05',
    verification: 'pendente'
  }
];

return provisions.map((p) => ({ json: { ...cfg, ...p } }));

// Constrói o UPSERT idempotente (CTE) para um dispositivo.
// Lê os campos do item original via paired-item ($('Load Provisions').item)
// e o embedding da resposta da OpenAI ($json.data[0].embedding).
const src = $('Load Provisions').item.json;
const emb = $json.data[0].embedding;
const vec = '[' + emb.join(',') + ']';

const esc = (s) => String(s).replace(/'/g, "''");
const lit = (s) => (s === null || s === undefined || s === '') ? 'NULL' : `'${esc(s)}'`;
const dat = (s) => (s === null || s === undefined || s === '') ? 'NULL' : `'${esc(s)}'::date`;
const verif = (s) => `'${esc(s || 'pendente')}'::legal.verification_status`;

const query = `WITH s AS (
  INSERT INTO legal.source (source_type, title, url, authority, official)
  VALUES ('norma', ${lit(src.source_title)}, ${lit(src.source_url)}, 'Planalto', true)
  ON CONFLICT (source_type, url) WHERE url IS NOT NULL DO UPDATE SET title = EXCLUDED.title
  RETURNING id
),
n AS (
  INSERT INTO legal.norm (source_id, short_name, official_id, practice_area)
  SELECT s.id, ${lit(src.norm_short_name)}, ${lit(src.norm_official_id)}, ${lit(src.practice_area)}::legal.practice_area FROM s
  ON CONFLICT (short_name) DO UPDATE SET official_id = EXCLUDED.official_id
  RETURNING id
),
p AS (
  INSERT INTO legal.norm_provision (norm_id, label, citation_key)
  SELECT n.id, ${lit(src.label)}, ${lit(src.citation_key)} FROM n
  ON CONFLICT (norm_id, citation_key) DO UPDATE SET label = EXCLUDED.label
  RETURNING id
),
v AS (
  INSERT INTO legal.norm_version (provision_id, full_text, amended_by, valid_from, source_id, verification, embedding)
  SELECT p.id, ${lit(src.full_text)}, ${lit(src.amended_by)}, ${dat(src.valid_from)}, s.id, ${verif(src.verification)}, '${vec}'::vector
  FROM p CROSS JOIN s
  ON CONFLICT (provision_id, content_hash) DO NOTHING
  RETURNING id
)
INSERT INTO legal.document_chunk (source_id, ref_table, ref_id, chunk_index, content, embedding)
SELECT s.id, 'norm_version', v.id, 0, ${lit(src.full_text)}, '${vec}'::vector
FROM v CROSS JOIN s
ON CONFLICT (ref_table, ref_id, chunk_index) DO NOTHING;`;

return { json: { citation_key: src.citation_key, query } };
